 p_id=>wwv_flow_imp.id(116285939354220890818)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_SALVARE_REZ'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_rental_id NUMBER;',
'BEGIN',
unistr('    -- 1. Inser\0103m \00EEn tabelul principal RENTALS'),
unistr('    -- Not\0103: Folosim RENTALS_SEQ2 pentru a genera un ID unic'),
'    INSERT INTO RENTALS (',
'        RentalID, ',
'        CustomerID, ',
'        StartDate, ',
'        EndDate, ',
'        Status',
'    )',
'    VALUES (',
'        RENTALS_SEQ2.NEXTVAL, ',
'        :P2_CUSTOMER_NAME, -- APEX preia ID-ul returnat de Select List',
'        :P2_STARTDATE, ',
'        :P2_ENDDATE, ',
'        ''Activ''',
'    )',
'    RETURNING RentalID INTO v_rental_id;',
'',
unistr('    -- 2. Inser\0103m \00EEn tabelul de detalii RENTALITEMS'),
'    INSERT INTO RENTALITEMS (',
'        RentalID, ',
'        MovieID, ',
'        Quantity',
'    )',
'    VALUES (',
'        v_rental_id, ',
'        :P2_MOVIE_NAME, -- APEX preia MovieID-ul returnat de Select List',
unistr('        NVL(:P2_QUANTITY, 1) -- Dac\0103 e gol, punem implicit 1'),
'    );',
'',
unistr('    -- 3. Actualiz\0103m stocul filmului \00EEn tabelul MOVIE'),
'    UPDATE MOVIE ',
'    SET Stock = Stock - NVL(:P2_QUANTITY, 1)',
'    WHERE MovieID = :P2_MOVIE_NAME;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>'Error #SQLERRM#'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_success_message=>'Succes!'
,p_internal_uid=>116285939354220890818
);
end;
