,p_plug_name=>'Calendar(Denisa)'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_escape_on_http_output=>'Y'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    R.RentalID AS ID,',
'    R.StartDate AS START_DATE,',
unistr('    -- Dac\0103 Statusul este ''active'', nu vrem o dat\0103 de sf\00E2r\0219it (END_DATE) pentru a marca evenimentul ca punct de \00EEnceput.'),
unistr('    -- Vom seta END_DATE la NULL sau o valoare mic\0103, dar cel mai sigur este s\0103 NU o select\0103m deloc.'),
unistr('    -- Totu\0219i, APEX Calendar Region necesit\0103 o coloan\0103 END_DATE. O putem seta la StartDate + 1 zi, sau o putem ignora.'),
unistr('    -- CEL MAI SIGUR: S\0103 ignor\0103m coloana END_DATE pentru ''active'' sau s\0103 o set\0103m la START_DATE.'),
'',
unistr('    R.StartDate AS END_DATE, -- Folosim StartDate \0219i ca EndDate pentru a avea o durat\0103 de 1 zi (sau un punct)'),
'',
unistr('    -- Combin\0103m toate titlurile filmelor \00EEnchiriate \00EEntr-un singur r\00E2nd (folosind LISTAGG)'),
'    (',
'        SELECT',
'            LISTAGG(M.Title, '', '') WITHIN GROUP (ORDER BY M.Title)',
'        FROM RENTALITEMS RI_INNER',
'        JOIN MOVIE M ON M.MovieID = RI_INNER.MovieID',
'        WHERE RI_INNER.RentalID = R.RentalID',
'    ) || '' - '' || C.FirstName || '' '' || C.LastName AS TITLE',
'',
'FROM RENTALS R',
'JOIN CUSTOMERS C ON C.CustomerID = R.CustomerID',
'WHERE R.Status = ''active''',
'ORDER BY R.StartDate;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CSS_CALENDAR'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'additional_calendar_views', 'list:navigation',
  'display_column', 'TITLE',
  'drag_and_drop', 'N',
  'end_date_column', 'END_DATE',
  'event_sorting', 'AUTOMATIC',
  'maximum_events_day', '10',
  'multiple_line_event', 'Y',
  'primary_key_column', 'ID',
  'show_time', 'N',
  'show_tooltip', 'Y',
  'show_weekend', 'Y',
  'start_date_column', 'START_DATE')).to_clob
);
end;
