 p_id=>28
,p_name=>'Hierarchy-movies by genre'
,p_alias=>'HIERARCHY-MOVIES-BY-GENRE'
,p_step_title=>'Hierarchy-movies by genre'
,p_autocomplete_on_off=>'OFF'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'20'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(259857733060957212568)
,p_plug_name=>'New'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    t.NODE_ID,',
'    t.PARENT_NODE_ID,',
'    t.NODE_NAME',
'FROM (',
'',
'    SELECT',
'        Genre AS NODE_ID,',
'        NULL AS PARENT_NODE_ID,',
'        Genre AS NODE_NAME',
'    FROM (',
'        SELECT DISTINCT Genre FROM MOVIE',
'    ) g',
'    WHERE Genre IS NOT NULL ',
'',
'    UNION ALL',
'',
'',
'    SELECT',
'        ''NOGENRE'' AS NODE_ID, ',
'        NULL AS PARENT_NODE_ID,     ',
'        ''NOGENRE'' AS NODE_NAME',
'    FROM DUAL',
') t',
'',
'UNION ALL',
'',
'',
'SELECT',
'    TO_CHAR(MovieID) AS NODE_ID,',
unistr('    COALESCE(Genre, ''NOGENRE'') AS PARENT_NODE_ID, -- Dac\0103 Genre este NULL, folose\0219te ''NOGENRE'' ca p\0103rinte'),
'    Title AS NODE_NAME',
'FROM MOVIE',
'ORDER BY PARENT_NODE_ID, NODE_NAME;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_JSTREE'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'activate_node_link_with', 'S',
  'default_icon_css_class', 'icon-tree-folder',
